\nimport \'package:flutter/material.dart\';\nimport \'package:jaldevi_hd_music_book_program/domain/entities/package.dart\';\nimport \'package:jaldevi_hd_music_book_program/presentation/screens/booking/booking_screen.dart\';\n\nclass PackageDetailsScreen extends StatelessWidget {\n  final Package package;\n\n  const PackageDetailsScreen({super.key, required this.package});\n\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: Text(package.name),\n      ),\n      body: SingleChildScrollView(\n        padding: const EdgeInsets.all(16.0),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.stretch,\n          children: [\n            Image.network(package.imageUrl, height: 200, fit: BoxFit.cover),\n            const SizedBox(height: 16.0),\n            Text(\n              package.name,\n              style: Theme.of(context).textTheme.headline5,\n            ),\n            const SizedBox(height: 8.0),\n            Text(\n              package.description,\n              style: Theme.of(context).textTheme.bodyText2,\n            ),\n            const SizedBox(height: 16.0),\n            Text(\n              \'Price: \$${package.price}\',\n              style: Theme.of(context).textTheme.headline6,\n            ),\n            const SizedBox(height: 16.0),\n            _buildSection(\n              context,\n              \'Included Equipment\',\n              package.includedEquipment,\n            ),\n            const SizedBox(height: 16.0),\n            _buildSection(\n              context,\n              \'Included Staff\',\n              package.includedStaff,\n            ),\n            const SizedBox(height: 24.0),\n            ElevatedButton(\n              onPressed: () {\n                Navigator.of(context).push(\n                  MaterialPageRoute(\n                    builder: (context) => BookingScreen(package: package),\n                  ),\n                );\n              },\n              child: const Text(\'Book Now\'),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget _buildSection(BuildContext context, String title, List<String> items) {\n    return Column(\n      crossAxisAlignment: CrossAxisAlignment.start,\n      children: [\n        Text(\n          title,\n          style: Theme.of(context).textTheme.headline6,\n        ),\n        const SizedBox(height: 8.0),\n        ...items.map((item) => Text(\' - $item\')),\n      ],\n    );\n  }\n}\n